import React, { useState, useEffect } from 'react';
import './Projects.css';

/* Fallback sample data shown when the API is unreachable */
const FALLBACK_PROJECTS = [
  {
    id: 1,
    title: 'ShopSphere',
    description: 'Full-featured e-commerce platform with real-time inventory, Stripe payments, and an admin dashboard. Built with Next.js, Node.js, and PostgreSQL.',
    tags: ['Next.js', 'Node.js', 'PostgreSQL', 'Stripe'],
    live_url: 'https://example.com',
    repo_url: 'https://github.com',
    featured: true,
  },
  {
    id: 2,
    title: 'TaskFlow',
    description: 'Kanban-style project management app with drag-and-drop, real-time collaboration via WebSockets, and role-based access control.',
    tags: ['React', 'Socket.io', 'MongoDB', 'Express'],
    live_url: 'https://example.com',
    repo_url: 'https://github.com',
    featured: true,
  },
  {
    id: 3,
    title: 'DevMetrics',
    description: 'Developer analytics dashboard that aggregates GitHub activity, deploys, and CI metrics into a single, unified view.',
    tags: ['React', 'D3.js', 'GitHub API', 'Python'],
    live_url: 'https://example.com',
    repo_url: 'https://github.com',
    featured: false,
  },
  {
    id: 4,
    title: 'PodcastAI',
    description: 'AI-powered podcast summariser that generates chapters, transcripts, and key takeaways using OpenAI Whisper and GPT-4.',
    tags: ['Python', 'FastAPI', 'OpenAI', 'React'],
    live_url: 'https://example.com',
    repo_url: 'https://github.com',
    featured: false,
  },
];

function ProjectCard({ project, index }) {
  return (
    <article
      className={`project-card ${project.featured ? 'project-card--featured' : ''}`}
      style={{ animationDelay: `${index * 0.1}s` }}
    >
      {project.featured && (
        <span className="project-card__badge">Featured</span>
      )}

      {/* Thumbnail placeholder */}
      <div className="project-card__thumb" aria-hidden="true">
        <span className="project-card__thumb-letter">
          {project.title.charAt(0)}
        </span>
      </div>

      <div className="project-card__body">
        <h3 className="project-card__title">{project.title}</h3>
        <p className="project-card__desc">{project.description}</p>

        {/* Tags */}
        <div className="project-card__tags">
          {project.tags.map(tag => (
            <span key={tag} className="project-card__tag">{tag}</span>
          ))}
        </div>

        {/* Links */}
        <div className="project-card__links">
          {project.live_url && (
            <a
              href={project.live_url}
              target="_blank"
              rel="noopener noreferrer"
              className="project-card__link project-card__link--live"
            >
              ↗ Live Demo
            </a>
          )}
          {project.repo_url && (
            <a
              href={project.repo_url}
              target="_blank"
              rel="noopener noreferrer"
              className="project-card__link"
            >
              ⌥ Source Code
            </a>
          )}
        </div>
      </div>
    </article>
  );
}

function Projects() {
  const [projects, setProjects] = useState([]);
  const [status,   setStatus]   = useState('loading'); /* loading | success | error */

  useEffect(() => {
    const controller = new AbortController();

    fetch('http://localhost:5000/projects', { signal: controller.signal })
      .then(res => {
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        return res.json();
      })
      .then(data => {
        setProjects(Array.isArray(data) ? data : FALLBACK_PROJECTS);
        setStatus('success');
      })
      .catch(err => {
        if (err.name === 'AbortError') return;
        console.warn('Projects API unavailable — using fallback data.', err.message);
        setProjects(FALLBACK_PROJECTS);
        setStatus('error');
      });

    return () => controller.abort();
  }, []);

  return (
    <section id="projects" className="projects">
      <div className="container">
        <p className="section-tag">My work</p>
        <h2 className="section-title">Selected Projects</h2>

        {status === 'error' && (
          <p className="projects__notice">
            ⚠ API unreachable — showing sample projects.
          </p>
        )}

        {status === 'loading' ? (
          <div className="projects__skeleton-grid">
            {[1, 2, 3, 4].map(n => (
              <div key={n} className="project-skeleton" />
            ))}
          </div>
        ) : (
          <div className="projects__grid">
            {projects.map((project, i) => (
              <ProjectCard key={project.id ?? i} project={project} index={i} />
            ))}
          </div>
        )}
      </div>
    </section>
  );
}

export default Projects;
